  `source` = IF(`geo_cities`.`lat` IS NOT NULL AND `geo_cities`.`source` = 'seed', 'seed', VALUES(`source`)),
  `lat` = COALESCE(`geo_cities`.`lat`, VALUES(`lat`)),
  `lng` = COALESCE(`geo_cities`.`lng`, VALUES(`lng`)),
  `is_active` = 1;
